# Add album library song IDs
for album in album_library:
    for song_id in album['song_ids']:
        all_song_ids.add(song_id)

# Add playlist library song IDs
for playlist in playlist_library:
    for song_id in playlist['song_ids']:
        all_song_ids.add(song_id)

print("Unique song count:", len(all_song_ids))
print("Unique song IDs:", sorted(all_song_ids))

